	int count_bad(int L, int R, int p, int pl, int pr, const int x) {
		if (pl > R or pr < L)return 0;

		// 剪枝，当前区间的 gcd 是 x 的倍数
		if (info[p].x % x == 0)return 0;

		// 叶子节点，且区间 gcd 不是 x 的倍数
		if (pl == pr)return 1;

		int mid = pl + pr >> 1;
		int cnt = count_bad(L, R, l(p), pl, mid, x);
		if (cnt > 1)return cnt; // 剪枝，左边已经不满足条件

		cnt += count_bad(L, R, r(p), mid + 1, pr, x);
		return cnt;
	}
	int count_bad(int l, int r, const int x) {
		return count_bad(l, r, 1, 1, n, x);
	}

struct Info {
	Info() : x(0) {};
	Info(int x) : x(x) {};

	// 要维护的值
	int x;
	void apply(const Info& v) {
		// 如何单点修改
		x = v.x;
	}
};
Info operator+(const Info& a, const Info& b) {
	Info c;
	c.x = Math::gcd(a.x, b.x);
	return c;
}

void solve(int CASE)
{
	int n; cin >> n;
	var a = vector<Info>(n + 1);
	fa(i, 1, n)cin >> a[i].x;
	var seg = SegmentTree<Info>(a);
	int q; cin >> q;
	while (q--) {
		int op; cin >> op;
		if (op == 1) {
			int l, r, x; cin >> l >> r >> x;

			// 区间的 gcd % x == 0 即可，因为可以随便改一个数
			int cnt = seg.count_bad(l, r, x);
			if (cnt <= 1)cout << "YES" << endl;
			else cout << "NO" << endl;
		}
		else {
			int id, x; cin >> id >> x;
			seg.modify(id, x);
		}
	}
	return;
}
